function Placeholder({ item }) {
  // 이미지 매핑
  const imgMap = {
    "sigung": IMG_SIGUNG,
    "agent_arch": IMG_AGENT_ARCH,
    "agent_steps": IMG_AGENT_STEPS,
    "carrot": IMG_CARROT,
  };
  const src = imgMap[item.imgKey];

  // 멀티 이미지
  if (item.type === "multi") {
    const imgMap2 = { "sigung": IMG_SIGUNG, "agent_arch": IMG_AGENT_ARCH, "agent_steps": IMG_AGENT_STEPS, "carrot": IMG_CARROT };
    return (
      <div style={{ margin: "12px 0", display: "flex", flexDirection: "column", gap: 8 }}>
        {item.images.map((img, i) => (
          <div key={i} style={{ borderRadius: 10, overflow: "hidden", border: `1px solid ${GRAY3}` }}>
            <img src={imgMap2[img.imgKey]} alt={img.caption} style={{ width: "100%", display: "block", objectFit: "contain" }} />
            {img.caption && (
              <div style={{ padding: "6px 12px", background: GRAY2, fontSize: 11, color: GRAY1, fontFamily: "sans-serif" }}>{img.caption}</div>
            )}
          </div>
        ))}
      </div>
    );
  }

  if (src) {
    return (
      <div style={{ margin: "12px 0", borderRadius: 10, overflow: "hidden", border: `1px solid ${GRAY3}` }}>
        <img src={src} alt={item.label} style={{ width: "100%", display: "block", objectFit: "contain" }} />
        {item.caption && (
          <div style={{ padding: "8px 12px", background: GRAY2, fontSize: 11, color: GRAY1, fontFamily: "sans-serif" }}>
            {item.caption}
          </div>
        )}
      </div>
    );
  }
  // 이미지 없는 경우 — 아무것도 렌더링 안 함
  return null;
}

