function Label({ text }) {
  return (
    <span style={{
      fontSize: 11, fontWeight: 700, color: BLUE,
      letterSpacing: "0.15em", textTransform: "uppercase", fontFamily: "sans-serif",
    }}>{text}</span>
  );
}

function Tag({ text, blue }) {
  return (
    <span style={{
      fontSize: 11, fontWeight: blue ? 600 : 400,
      color: blue ? BLUE : GRAY1,
      background: blue ? "#EBF3FF" : GRAY2,
      border: `1px solid ${blue ? "#BFDBFE" : GRAY3}`,
      borderRadius: 20, padding: "3px 10px", fontFamily: "sans-serif",
    }}>{text}</span>
  );
}

// ── Nav ──────────────────────────────────────────────────────────────────────
function Nav({ active }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);
  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
      height: 56, display: "flex", alignItems: "center",
      justifyContent: "space-between", padding: "0 40px",
      background: scrolled ? "rgba(255,255,255,0.96)" : WHITE,
      borderBottom: `1px solid ${scrolled ? GRAY3 : "transparent"}`,
      backdropFilter: scrolled ? "blur(8px)" : "none",
      transition: "all 0.2s",
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <div style={{ width: 28, height: 28, background: BLUE, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <span style={{ color: WHITE, fontSize: 12, fontWeight: 700, fontFamily: "sans-serif" }}>JY</span>
        </div>
        <span style={{ fontSize: 15, fontWeight: 700, color: DARK, fontFamily: "sans-serif" }}>양정윤</span>
      </div>
      <div style={{ display: "flex", gap: 32 }}>
        {NAV_LINKS.map(n => (
          <a key={n.id} href={`#${n.id}`} style={{
            fontSize: 14, fontWeight: active === n.id ? 600 : 400,
            color: active === n.id ? BLUE : GRAY1,
            textDecoration: "none", fontFamily: "sans-serif", transition: "color 0.15s",
          }}>{n.label}</a>
        ))}
      </div>
      <a href="mailto:yun110408@gmail.com" style={{
        fontSize: 13, fontWeight: 600, color: WHITE, background: BLUE,
        padding: "7px 16px", borderRadius: 8, textDecoration: "none", fontFamily: "sans-serif",
      }}>연락하기</a>
    </nav>
  );
}

