        cursor: "pointer", transition: "all 0.2s",
        boxShadow: hover ? "0 4px 16px rgba(49,130,246,0.1)" : "none",
        transform: hover ? "translateY(-2px)" : "translateY(0)",
        display: featured ? "grid" : "block",
